using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Provides offline-first data persistence using IndexedDB via JS interop.
/// </summary>
public interface ILocalStorageService
{
    Task InitializeAsync();
    Task<List<ConstructionSite>> GetSitesAsync();
    Task SaveSiteAsync(ConstructionSite site);
    Task DeleteSiteAsync(string siteId);
    Task<List<Inspection>> GetInspectionsAsync(string? siteId = null);
    Task<Inspection?> GetInspectionAsync(string inspectionId);
    Task SaveInspectionAsync(Inspection inspection);
    Task<List<Inspection>> GetUnsyncedInspectionsAsync();
    Task MarkAsSyncedAsync(string inspectionId);
}

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbStorageService : ILocalStorageService
{
    private readonly IJSRuntime _js;
    private bool _initialized;

    public IndexedDbStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        if (_initialized) return;
        await _js.InvokeVoidAsync("siteInspectorDb.initialize");
        _initialized = true;
    }

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        await InitializeAsync();
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getAll", "sites");
        return JsonSerializer.Deserialize<List<ConstructionSite>>(json) ?? new();
    }

    public async Task SaveSiteAsync(ConstructionSite site)
    {
        await InitializeAsync();
        var json = JsonSerializer.Serialize(site);
        await _js.InvokeVoidAsync("siteInspectorDb.put", "sites", site.Id, json);
    }

    public async Task DeleteSiteAsync(string siteId)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("siteInspectorDb.delete", "sites", siteId);
    }

    public async Task<List<Inspection>> GetInspectionsAsync(string? siteId = null)
    {
        await InitializeAsync();
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getAll", "inspections");
        var inspections = JsonSerializer.Deserialize<List<Inspection>>(json) ?? new();
        if (siteId != null)
            inspections = inspections.Where(i => i.SiteId == siteId).ToList();
        return inspections.OrderByDescending(i => i.InspectedAt).ToList();
    }

    public async Task<Inspection?> GetInspectionAsync(string inspectionId)
    {
        await InitializeAsync();
        var json = await _js.InvokeAsync<string?>("siteInspectorDb.get", "inspections", inspectionId);
        if (json == null) return null;
        return JsonSerializer.Deserialize<Inspection>(json);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await InitializeAsync();
        var json = JsonSerializer.Serialize(inspection);
        await _js.InvokeVoidAsync("siteInspectorDb.put", "inspections", inspection.Id, json);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        await InitializeAsync();
        var all = await GetInspectionsAsync();
        return all.Where(i => !i.IsSynced).ToList();
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection != null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }
}

using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Monitors connectivity and syncs unsynced inspections to the server when online.
/// </summary>
public class SyncService : IAsyncDisposable
{
    private readonly ILocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private bool _isSyncing;

    public event Action? OnSyncStatusChanged;
    public bool IsOnline { get; private set; } = true;
    public int PendingCount { get; private set; }
    public bool IsSyncing => _isSyncing;
    public string? LastError { get; private set; }

    public SyncService(ILocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("siteInspectorSync.initialize", _dotNetRef);
        IsOnline = await _js.InvokeAsync<bool>("siteInspectorSync.isOnline");
        await UpdatePendingCountAsync();
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnSyncStatusChanged?.Invoke();

        if (isOnline)
        {
            await SyncAsync();
        }
    }

    public async Task SyncAsync()
    {
        if (_isSyncing || !IsOnline) return;

        _isSyncing = true;
        LastError = null;
        OnSyncStatusChanged?.Invoke();

        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            foreach (var inspection in unsynced)
            {
                var response = await _http.PostAsJsonAsync("/api/inspections", inspection);
                if (response.IsSuccessStatusCode)
                {
                    await _storage.MarkAsSyncedAsync(inspection.Id);
                }
            }
        }
        catch (Exception ex)
        {
            LastError = ex.Message;
        }
        finally
        {
            _isSyncing = false;
            await UpdatePendingCountAsync();
            OnSyncStatusChanged?.Invoke();
        }
    }

    public async Task UpdatePendingCountAsync()
    {
        var unsynced = await _storage.GetUnsyncedInspectionsAsync();
        PendingCount = unsynced.Count;
    }

    public async ValueTask DisposeAsync()
    {
        if (_dotNetRef != null)
        {
            await _js.InvokeVoidAsync("siteInspectorSync.dispose");
            _dotNetRef.Dispose();
        }
    }
}

