// IndexedDB wrapper for offline data storage
window.siteInspectorDb = {
    db: null,

    initialize: async function () {
        if (this.db) return;

        return new Promise((resolve, reject) => {
            const request = indexedDB.open('SiteInspectorDB', 1);

            request.onupgradeneeded = (event) => {
                const db = event.target.result;
                if (!db.objectStoreNames.contains('sites')) {
                    db.createObjectStore('sites', { keyPath: 'key' });
                }
                if (!db.objectStoreNames.contains('inspections')) {
                    db.createObjectStore('inspections', { keyPath: 'key' });
                }
            };

            request.onsuccess = (event) => {
                this.db = event.target.result;
                resolve();
            };

            request.onerror = (event) => {
                reject(event.target.error);
            };
        });
    },

    put: async function (storeName, key, json) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            store.put({ key: key, data: json });
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    get: async function (storeName, key) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.get(key);
            request.onsuccess = () => {
                resolve(request.result ? request.result.data : null);
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAll: async function (storeName) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => {
                const items = request.result.map(r => JSON.parse(r.data));
                resolve(JSON.stringify(items));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    delete: async function (storeName, key) {
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            store.delete(key);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    }
};

// Connectivity monitoring and sync triggers
window.siteInspectorSync = {
    dotNetRef: null,

    initialize: function (dotNetRef) {
        this.dotNetRef = dotNetRef;
        window.addEventListener('online', () => this.notifyConnectivityChange(true));
        window.addEventListener('offline', () => this.notifyConnectivityChange(false));
    },

    notifyConnectivityChange: function (isOnline) {
        if (this.dotNetRef) {
            this.dotNetRef.invokeMethodAsync('OnConnectivityChanged', isOnline);
        }
    },

    isOnline: function () {
        return navigator.onLine;
    },

    dispose: function () {
        this.dotNetRef = null;
    }
};

// Camera/photo capture helper
window.siteInspectorCamera = {
    capturePhoto: function (inputElement) {
        return new Promise((resolve) => {
            inputElement.onchange = async (e) => {
                const file = e.target.files[0];
                if (!file) { resolve(null); return; }

                // Resize for mobile efficiency
                const bitmap = await createImageBitmap(file);
                const maxDim = 1200;
                let w = bitmap.width, h = bitmap.height;
                if (w > maxDim || h > maxDim) {
                    const ratio = Math.min(maxDim / w, maxDim / h);
                    w = Math.round(w * ratio);
                    h = Math.round(h * ratio);
                }

                const canvas = document.createElement('canvas');
                canvas.width = w;
                canvas.height = h;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(bitmap, 0, 0, w, h);

                const base64 = canvas.toDataURL('image/jpeg', 0.7);
                resolve(JSON.stringify({
                    fileName: file.name,
                    base64Data: base64,
                    takenAt: new Date().toISOString()
                }));
            };
            inputElement.click();
        });
    }
};

