@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@using System.Text.Json
@inject ILocalStorageService Storage
@inject NavigationManager Nav
@inject SyncService Sync
@inject IJSRuntime JS

<PageTitle>New Inspection</PageTitle>

<div class="page-header">
    <button class="btn btn-outline-secondary btn-sm" @onclick='() => Nav.NavigateTo($"/site/{SiteId}")'>← Back</button>
    <h1>New Inspection</h1>
</div>

<div class="mb-3">
    <label class="form-label">Inspector Name</label>
    <input @bind="_inspectorName" @bind:event="oninput" class="form-control" placeholder="Your name" />
</div>

<div class="checklist-progress mb-3">
    <div class="progress">
        <div class="progress-bar bg-success" style="width: @PassPercent%"></div>
        <div class="progress-bar bg-danger" style="width: @FailPercent%"></div>
        <div class="progress-bar bg-secondary" style="width: @NaPercent%"></div>
    </div>
    <small class="text-muted">@CheckedCount / @_checklist.Count checked</small>
</div>

@foreach (var category in _checklist.GroupBy(c => c.Category))
{
    <h3 class="checklist-category">@category.Key</h3>
    @foreach (var item in category)
    {
        <div class="checklist-item @GetItemClass(item)">
            <div class="checklist-item-text">@item.Description</div>
            <div class="checklist-buttons">
                <button class="btn-check-status @(item.Status == CheckStatus.Pass ? "active-pass" : "")"
                        @onclick="() => SetStatus(item, CheckStatus.Pass)">✓</button>
                <button class="btn-check-status @(item.Status == CheckStatus.Fail ? "active-fail" : "")"
                        @onclick="() => SetStatus(item, CheckStatus.Fail)">✗</button>
                <button class="btn-check-status @(item.Status == CheckStatus.NotApplicable ? "active-na" : "")"
                        @onclick="() => SetStatus(item, CheckStatus.NotApplicable)">N/A</button>
            </div>
            @if (item.Status == CheckStatus.Fail)
            {
                <input @bind="item.Notes" @bind:event="oninput" class="form-control mt-1 checklist-note"
                       placeholder="Note required for failures..." />
            }
        </div>
    }
}

<div class="mt-4 mb-3">
    <h3>📷 Photos</h3>
    <button class="btn btn-outline-primary" @onclick="TakePhoto">Add Photo</button>
    <input type="file" accept="image/*" capture="environment" @ref="_fileInput"
           @onchange="OnPhotoSelected" style="display:none" />

    @if (_photos.Count > 0)
    {
        <div class="photo-grid mt-2">
            @foreach (var photo in _photos)
            {
                <div class="photo-thumb">
                    <img src="@photo.Base64Data" alt="@photo.Caption" />
                    <input @bind="photo.Caption" @bind:event="oninput" class="form-control form-control-sm mt-1"
                           placeholder="Caption..." />
                </div>
            }
        </div>
    }
</div>

<div class="mb-3">
    <label class="form-label">General Notes</label>
    <textarea @bind="_notes" @bind:event="oninput" class="form-control" rows="3"
              placeholder="Additional observations..."></textarea>
</div>

<button class="btn btn-success btn-lg w-100 mb-4" @onclick="SaveInspection"
        disabled="@string.IsNullOrWhiteSpace(_inspectorName)">
    💾 Save Inspection
</button>

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private string _inspectorName = string.Empty;
    private string _notes = string.Empty;
    private List<ChecklistItem> _checklist = new();
    private List<InspectionPhoto> _photos = new();
    private ElementReference _fileInput;

    private int CheckedCount => _checklist.Count(c => c.Status != CheckStatus.NotChecked);
    private double PassPercent => _checklist.Count == 0 ? 0 : _checklist.Count(c => c.Status == CheckStatus.Pass) * 100.0 / _checklist.Count;
    private double FailPercent => _checklist.Count == 0 ? 0 : _checklist.Count(c => c.Status == CheckStatus.Fail) * 100.0 / _checklist.Count;
    private double NaPercent => _checklist.Count == 0 ? 0 : _checklist.Count(c => c.Status == CheckStatus.NotApplicable) * 100.0 / _checklist.Count;

    protected override void OnInitialized()
    {
        _checklist = DefaultChecklist.CreateSafetyChecklist();
    }

    private void SetStatus(ChecklistItem item, CheckStatus status)
    {
        item.Status = item.Status == status ? CheckStatus.NotChecked : status;
    }

    private string GetItemClass(ChecklistItem item) => item.Status switch
    {
        CheckStatus.Pass => "item-pass",
        CheckStatus.Fail => "item-fail",
        CheckStatus.NotApplicable => "item-na",
        _ => ""
    };

    private async Task TakePhoto()
    {
        await JS.InvokeVoidAsync("siteInspectorCamera.triggerFileInput", _fileInput);
    }

    private async Task OnPhotoSelected()
    {
        var json = await JS.InvokeAsync<string?>("siteInspectorCamera.readPhoto", _fileInput);
        if (json != null)
        {
            var photoData = JsonSerializer.Deserialize<InspectionPhoto>(json, new JsonSerializerOptions
            {
                PropertyNameCaseInsensitive = true
            });
            if (photoData != null)
            {
                photoData.Id = Guid.NewGuid().ToString();
                _photos.Add(photoData);
            }
        }
    }

    private async Task SaveInspection()
    {
        if (string.IsNullOrWhiteSpace(_inspectorName)) return;

        var sites = await Storage.GetSitesAsync();
        var site = sites.FirstOrDefault(s => s.Id == SiteId);

        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = site?.Name ?? "Unknown",
            InspectorName = _inspectorName.Trim(),
            Notes = _notes.Trim(),
            Checklist = _checklist,
            Photos = _photos,
            IsSynced = false
        };

        await Storage.SaveInspectionAsync(inspection);
        await Sync.UpdatePendingCountAsync();

        if (Sync.IsOnline)
        {
            _ = Sync.SyncAsync();
        }

        Nav.NavigateTo($"/site/{SiteId}");
    }
}

