@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Inspection Report</PageTitle>

@if (_inspection == null)
{
    <p class="text-muted">Loading...</p>
}
else
{
    <div class="page-header">
        <button class="btn btn-outline-secondary btn-sm" @onclick='() => Nav.NavigateTo($"/site/{_inspection.SiteId}")'>← Back</button>
        <h1>Inspection Report</h1>
    </div>

    <div class="card mb-3">
        <div class="card-body">
            <p><strong>Site:</strong> @_inspection.SiteName</p>
            <p><strong>Inspector:</strong> @_inspection.InspectorName</p>
            <p><strong>Date:</strong> @_inspection.InspectedAt.ToLocalTime().ToString("MMMM dd, yyyy h:mm tt")</p>
            <p>
                <strong>Status:</strong>
                <span class="badge @(_inspection.IsSynced ? "bg-success" : "bg-warning")">
                    @(_inspection.IsSynced ? "Synced" : "Pending Sync")
                </span>
            </p>
        </div>
    </div>

    <h2>Checklist Results</h2>
    <div class="results-summary mb-3">
        <span class="badge bg-success">✓ @_inspection.Checklist.Count(c => c.Status == CheckStatus.Pass) Pass</span>
        <span class="badge bg-danger">✗ @_inspection.Checklist.Count(c => c.Status == CheckStatus.Fail) Fail</span>
        <span class="badge bg-secondary">N/A @_inspection.Checklist.Count(c => c.Status == CheckStatus.NotApplicable)</span>
        <span class="badge bg-light text-dark">— @_inspection.Checklist.Count(c => c.Status == CheckStatus.NotChecked) Not Checked</span>
    </div>

    @foreach (var category in _inspection.Checklist.GroupBy(c => c.Category))
    {
        <h3 class="checklist-category">@category.Key</h3>
        @foreach (var item in category)
        {
            <div class="checklist-item @GetItemClass(item)">
                <div class="d-flex justify-content-between">
                    <span>@item.Description</span>
                    <span class="fw-bold">@GetStatusIcon(item.Status)</span>
                </div>
                @if (!string.IsNullOrWhiteSpace(item.Notes))
                {
                    <div class="text-muted small mt-1">📝 @item.Notes</div>
                }
            </div>
        }
    }

    @if (_inspection.Photos.Count > 0)
    {
        <h2 class="mt-4">Photos (@_inspection.Photos.Count)</h2>
        <div class="photo-grid">
            @foreach (var photo in _inspection.Photos)
            {
                <div class="photo-thumb">
                    <img src="@photo.Base64Data" alt="@photo.Caption" />
                    @if (!string.IsNullOrWhiteSpace(photo.Caption))
                    {
                        <small class="text-muted">@photo.Caption</small>
                    }
                </div>
            }
        </div>
    }

    @if (!string.IsNullOrWhiteSpace(_inspection.Notes))
    {
        <h2 class="mt-4">Notes</h2>
        <div class="card">
            <div class="card-body">@_inspection.Notes</div>
        </div>
    }
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(InspectionId);
    }

    private string GetItemClass(ChecklistItem item) => item.Status switch
    {
        CheckStatus.Pass => "item-pass",
        CheckStatus.Fail => "item-fail",
        CheckStatus.NotApplicable => "item-na",
        _ => ""
    };

    private string GetStatusIcon(CheckStatus status) => status switch
    {
        CheckStatus.Pass => "✓",
        CheckStatus.Fail => "✗",
        CheckStatus.NotApplicable => "N/A",
        _ => "—"
    };
}
