{"file_text": "@page "/sync"
@using SiteInspector.Client.Services
@inject SyncService Sync
@implements IDisposable

<PageTitle>Sync Status</PageTitle>

<div class="page-header">
    <h1>📡 Sync Status</h1>
</div>

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex align-items-center gap-2 mb-2">
            <span class="status-dot @(Sync.IsOnline ? "online" : "offline")"></span>
            <strong>@(Sync.IsOnline ? "Online" : "Offline")</strong>
        </div>

        <p class="mb-1">
            <strong>Pending uploads:</strong> @Sync.PendingCount inspection(s)
        </p>

        @if (Sync.IsSyncing)
        {
            <div class="text-primary">
                <span class="spinner-border spinner-border-sm"></span> Syncing...
            </div>
        }

        @if (!string.IsNullOrEmpty(Sync.LastError))
        {
            <div class="alert alert-warning mt-2">
                <strong>Last error:</strong> @Sync.LastError
            </div>
        }
    </div>
</div>

<button class="btn btn-primary btn-lg w-100" @onclick="TriggerSync"
        disabled="@(!Sync.IsOnline || Sync.IsSyncing || Sync.PendingCount == 0)">
    🔄 Sync Now
</button>

<div class="mt-4">
    <h2>How Sync Works</h2>
    <ul class="text-muted">
        <li>Inspections are saved locally on your device first</li>
        <li>When online, data automatically uploads to the server</li>
        <li>You can work fully offline — nothing is lost</li>
        <li>Tap "Sync Now" to manually trigger upload</li>
    </ul>
</div>

@code {
    protected override void OnInitialized()
    {
        Sync.OnSyncStatusChanged += OnStatusChanged;
    }

    private async Task TriggerSync()
    {
        await Sync.SyncAsync();
    }

    private void OnStatusChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Sync.OnSyncStatusChanged -= OnStatusChanged;
    }
}
", "path": "/tmp/sv-884dae2255af4b70958c6e9c5e5422f7/SiteInspector/SiteInspector.Client/Pages/SyncStatus.razor"}

